import type { ScoreResult } from '../types';
import { invokeJudge } from './llmJudge';

export async function scoreContentExhaustiveness(
  input: string,
  output: string
): Promise<ScoreResult> {
  const prompt = `You are an expert Contentful Data Architect evaluating an ETL pipeline.
Evaluate whether an AI agent extracted ALL relevant text from the source document without dropping anything.

### INPUT PROVIDED TO THE AGENT (Markdown + Schema Definitions):
${input}

### ACTUAL OUTPUT GENERATED BY THE AGENT (Contentful JSON):
${output}

### EVALUATION CRITERION:
**Exhaustiveness (No Dropped Content):** Did the agent consider EVERY piece of content in the source document?
Verify that all non-context text was mapped to a field across the generated Content Types, and nothing was skipped, dropped, or heavily truncated.

Return ONLY valid JSON in this exact format (no markdown fences, no extra text):
{"score": <number 0.0–1.0>, "reason": "<1–2 sentences, quoting any dropped content>"}`;

  try {
    const { score, reason } = await invokeJudge(prompt);
    return { scorerId: 'content-exhaustiveness', score, reason };
  } catch (err) {
    return { scorerId: 'content-exhaustiveness', score: -1, reason: `Judge error: ${String(err)}` };
  }
}
